// Validate the variants array and normalize each entry into a consistent shape
const config = $json;
const variants = Array.isArray(config.variants) ? config.variants : [];

if (variants.length === 0) {
  throw new Error('No variants provided. POST body must include a variants array with at least one item.');
}

const normalized = variants.slice(0, 12).map((v, i) => ({
  id: (v.id || ('v' + (i + 1))).toString(),
  headline: (v.headline || '').toString().trim(),
  body: (v.body || v.description || '').toString().trim(),
  cta: (v.cta || '').toString().trim()
}));

return [{
  json: {
    brief: config.brief,
    icp: config.icp,
    brandVoice: config.brandVoice,
    platform: config.platform,
    submittedAt: config.submittedAt,
    variants: normalized,
    variantCount: normalized.length
  }
}];

