// Parse Claude's scores, merge with original variants and critic notes, sort by overall score
const variants = $('Normalize Variants Data').item.json.variants;
const submittedAt = $('Normalize Variants Data').item.json.submittedAt;
const platform = $('Normalize Variants Data').item.json.platform;
const critiqueRaw = $('Post to Claude for Critic Notes').item.json.content?.[0]?.text || '{}';
const scoreRaw = $json.content?.[0]?.text || '{}';

let critiques = [];
let scores = [];

try {
  const cleaned = critiqueRaw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  critiques = JSON.parse(cleaned).critiques || [];
} catch (e) {}

try {
  const cleaned = scoreRaw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  scores = JSON.parse(cleaned).scores || [];
} catch (e) {}

const byId = (arr, id) => arr.find(x => x.id === id) || {};

const merged = variants.map(v => {
  const c = byId(critiques, v.id);
  const s = byId(scores, v.id);
  return {
    id: v.id,
    headline: v.headline,
    body: v.body,
    cta: v.cta,
    hook: Number(s.hook) || 0,
    icp_fit: Number(s.icp_fit) || 0,
    brand_voice: Number(s.brand_voice) || 0,
    cta_clarity: Number(s.cta_clarity) || 0,
    overall: Number(s.overall) || 0,
    verdict: s.verdict || 'No verdict returned',
    top_fix: s.top_fix || '',
    strongest_line: c.strongest_line || '',
    weakest_line: c.weakest_line || '',
    hook_critique: c.hook_critique || '',
    submittedAt,
    platform
  };
});

merged.sort((a, b) => b.overall - a.overall);
merged.forEach((v, i) => { v.rank = i + 1; });

// Return one item per variant so Sheets append fires per variant
return merged.map(v => ({ json: v }));
